     1→/**
     2→ * Export Routes
     3→ *
     4→ * REST endpoints for exporting PM schedules (Excel/CSV) and generating reports (PDF).
     5→ * Uses async job processing with status polling.
     6→ *
     7→ * Key endpoints:
     8→ * - POST /export/pm-schedule - Queue PM schedule export
     9→ * - POST /export/report - Queue report generation
    10→ * - GET /export/:jobId - Get export job status and download URL
    11→ * - GET /export/jobs - List export jobs for current user
    12→ *
    13→ * @see specs/005-api.md Section 5.15
    14→ */
    15→
    16→import { Hono } from 'hono';
    17→import * as fs from 'node:fs';
    18→import * as path from 'node:path';
    19→import {
    20→  success,
    21→  paginatedSuccess,
    22→  error,
    23→  parsePaginationQuery,
    24→  ErrorCodes,
    25→  type AppVariables,
    26→} from '../types';
    27→import { getRequestId, getRequestDuration } from '../middleware/request-context';
    28→import {
    29→  getExportService,
    30→  type PmScheduleExportRequest,
    31→  type ReportExportRequest,
    32→  type ExportJobStatus,
    33→  type ReportType,
    34→} from '../../services/export';
    35→import { SYSTEM_USER_ID } from '../../lib/constants';
    36→
    37→// Reports output directory
    38→const REPORTS_OUTPUT_DIR = process.env['REPORTS_OUTPUT_DIR'] ?? '/tmp/mms-reports';
    39→
    40→// MIME type mapping for export files
    41→const MIME_TYPES: Record<string, string> = {
    42→  '.pdf': 'application/pdf',
    43→  '.xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    44→  '.csv': 'text/csv',
    45→};
    46→
    47→// Singleton service instance
    48→let exportService: ReturnType<typeof getExportService> | null = null;
    49→
    50→function getService(): ReturnType<typeof getExportService> {
    51→  if (!exportService) {
    52→    exportService = getExportService();
    53→  }
    54→  return exportService;
    55→}
    56→
    57→export const exportRoutes = new Hono<{ Variables: AppVariables }>();
    58→
    59→/**
    60→ * POST /export/pm-schedule
    61→ *
    62→ * Queue a PM schedule export job.
    63→ *
    64→ * Request Body:
    65→ * - format: Export format ('xlsx' or 'csv')
    66→ * - filters: Optional filters (depotId, fleetId, trainId, fromDate, toDate, status, pmTypeId, scenarioId)
    67→ * - columns: Optional list of columns to include
    68→ *
    69→ * Returns 202 Accepted with job ID for polling.
    70→ */
    71→exportRoutes.post('/export/pm-schedule', async (c) => {
    72→  const requestId = getRequestId(c);
    73→  const service = getService();
    74→
    75→  try {
    76→    const body = await c.req.json();
    77→
    78→    // Validate required fields
    79→    if (!body.format) {
    80→      return c.json(
    81→        error(ErrorCodes.VALIDATION_ERROR, 'format is required', requestId, {
    82→          field: 'format',
    83→          expected: ['xlsx', 'csv'],
    84→        }),
    85→        400
    86→      );
    87→    }
    88→
    89→    if (!['xlsx', 'csv'].includes(body.format)) {
    90→      return c.json(
    91→        error(ErrorCodes.VALIDATION_ERROR, 'Invalid format', requestId, {
    92→          field: 'format',
    93→          expected: ['xlsx', 'csv'],
    94→          received: body.format,
    95→        }),
    96→        400
    97→      );
    98→    }
    99→
   100→    // Get user from context (or use default for now)
   101→    const userId = c.get('user')?.id ?? SYSTEM_USER_ID;
   102→
   103→    const request: PmScheduleExportRequest = {
   104→      format: body.format,
   105→      filters: body.filters,
   106→      columns: body.columns,
   107→      requestedBy: userId,
   108→    };
   109→
   110→    const result = await service.queuePmScheduleExport(request);
   111→
   112→    return c.json(
   113→      success(
   114→        {
   115→          jobId: result.jobId,
   116→          status: result.status,
   117→          estimatedSizeBytes: result.estimatedSizeBytes,
   118→        },
   119→        { timing: { durationMs: getRequestDuration(c) } }
   120→      ),
   121→      202
   122→    );
   123→  } catch (err) {
   124→    const message = err instanceof Error ? err.message : 'Failed to queue export';
   125→    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   126→  }
   127→});
   128→
   129→/**
   130→ * POST /export/report
   131→ *
   132→ * Queue a report generation job.
   133→ *
   134→ * Request Body:
   135→ * - reportType: Type of report to generate
   136→ * - parameters: Report-specific parameters
   137→ *
   138→ * Report Types:
   139→ * - WEEKLY_COMPLIANCE: Weekly PM compliance summary
   140→ * - MONTHLY_SUMMARY: Monthly fleet maintenance summary
   141→ * - FLEET_STATUS: Current fleet status report
   142→ * - DRIFT_REPORT: Baseline drift analysis
   143→ * - TCO_PROJECTION: Total cost of ownership projection
   144→ * - BOW_WAVE_ANALYSIS: Maintenance clustering analysis
   145→ * - MANHOUR_UTILIZATION: Man-hour utilization report
   146→ *
   147→ * Returns 202 Accepted with job ID for polling.
   148→ */
   149→exportRoutes.post('/export/report', async (c) => {
   150→  const requestId = getRequestId(c);
   151→  const service = getService();
   152→
   153→  try {
   154→    const body = await c.req.json();
   155→
   156→    // Validate required fields
   157→    if (!body.reportType) {
   158→      return c.json(
   159→        error(ErrorCodes.VALIDATION_ERROR, 'reportType is required', requestId, {
   160→          field: 'reportType',
   161→        }),
   162→        400
   163→      );
   164→    }
   165→
   166→    const validTypes: ReportType[] = [
   167→      'WEEKLY_COMPLIANCE',
   168→      'MONTHLY_SUMMARY',
   169→      'FLEET_STATUS',
   170→      'DRIFT_REPORT',
   171→      'TCO_PROJECTION',
   172→      'BOW_WAVE_ANALYSIS',
   173→      'MANHOUR_UTILIZATION',
   174→    ];
   175→
   176→    if (!validTypes.includes(body.reportType)) {
   177→      return c.json(
   178→        error(ErrorCodes.VALIDATION_ERROR, 'Invalid reportType', requestId, {
   179→          field: 'reportType',
   180→          expected: validTypes,
   181→          received: body.reportType,
   182→        }),
   183→        400
   184→      );
   185→    }
   186→
   187→    // Get user from context (or use default for now)
   188→    const userId = c.get('user')?.id ?? SYSTEM_USER_ID;
   189→
   190→    const request: ReportExportRequest = {
   191→      reportType: body.reportType,
   192→      parameters: body.parameters ?? {},
   193→      requestedBy: userId,
   194→    };
   195→
   196→    const result = await service.queueReportExport(request);
   197→
   198→    return c.json(
   199→      success(
   200→        {
   201→          jobId: result.jobId,
   202→          status: result.status,
   203→          estimatedSizeBytes: result.estimatedSizeBytes,
   204→        },
   205→        { timing: { durationMs: getRequestDuration(c) } }
   206→      ),
   207→      202
   208→    );
   209→  } catch (err) {
   210→    const message = err instanceof Error ? err.message : 'Failed to queue report';
   211→    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   212→  }
   213→});
   214→
   215→/**
   216→ * GET /export/jobs
   217→ *
   218→ * List export jobs for the current user.
   219→ * NOTE: This route MUST be defined before /export/:jobId to avoid route collision.
   220→ *
   221→ * Query Parameters:
   222→ * - page: Page number (default: 1)
   223→ * - pageSize: Items per page (default: 20, max: 100)
   224→ * - status: Filter by status (comma-separated: QUEUED,PROCESSING,COMPLETED,FAILED,EXPIRED)
   225→ * - type: Filter by type (pm_schedule or report)
   226→ */
   227→exportRoutes.get('/export/jobs', async (c) => {
   228→  const requestId = getRequestId(c);
   229→  const service = getService();
   230→
   231→  try {
   232→    // Get user from context (or use default for now)
   233→    const userId = c.get('user')?.id ?? SYSTEM_USER_ID;
   234→
   235→    // Parse query parameters
   236→    const pagination = parsePaginationQuery({
   237→      page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
   238→      pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
   239→    });
   240→
   241→    // Parse status filter
   242→    let statusFilter: ExportJobStatus[] | undefined;
   243→    const statusParam = c.req.query('status');
   244→    if (statusParam) {
   245→      statusFilter = statusParam.split(',') as ExportJobStatus[];
   246→    }
   247→
   248→    // Parse type filter
   249→    const typeParam = c.req.query('type');
   250→    const typeFilter = typeParam === 'pm_schedule' || typeParam === 'report' ? typeParam : undefined;
   251→
   252→    const result = service.listExportJobs(userId, {
   253→      page: pagination.page,
   254→      pageSize: pagination.pageSize,
   255→      status: statusFilter,
   256→      type: typeFilter,
   257→    });
   258→
   259→    // Transform jobs to API response format
   260→    const jobs = result.jobs.map((job) => ({
   261→      jobId: job.id,
   262→      type: job.type,
   263→      status: job.status,
   264→      format: job.format,
   265→      createdAt: job.createdAt.toISOString(),
   266→      ...(job.completedAt && { completedAt: job.completedAt.toISOString() }),
   267→      ...(job.downloadUrl && { downloadUrl: job.downloadUrl }),
   268→      ...(job.expiresAt && { expiresAt: job.expiresAt.toISOString() }),
   269→      ...(job.fileSizeBytes && { fileSizeBytes: job.fileSizeBytes }),
   270→      ...(job.reportType && { reportType: job.reportType }),
   271→    }));
   272→
   273→    return c.json(
   274→      paginatedSuccess(jobs, {
   275→        page: pagination.page,
   276→        pageSize: pagination.pageSize,
   277→        totalItems: result.total,
   278→      }),
   279→      200
   280→    );
   281→  } catch (err) {
   282→    const message = err instanceof Error ? err.message : 'Failed to list export jobs';
   283→    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   284→  }
   285→});
   286→
   287→/**
   288→ * GET /export/:jobId
   289→ *
   290→ * Get export job status and download URL.
   291→ *
   292→ * Path Parameters:
   293→ * - jobId: Export job ID
   294→ *
   295→ * Response includes:
   296→ * - jobId: Job identifier
   297→ * - status: Current status (QUEUED, PROCESSING, COMPLETED, FAILED, EXPIRED)
   298→ * - downloadUrl: URL to download file (only when COMPLETED)
   299→ * - expiresAt: When the download URL expires
   300→ * - fileSizeBytes: Actual file size (only when COMPLETED)
   301→ * - errorMessage: Error details (only when FAILED)
   302→ */
   303→exportRoutes.get('/export/:jobId', async (c) => {
   304→  const requestId = getRequestId(c);
   305→  const service = getService();
   306→
   307→  try {
   308→    const jobId = c.req.param('jobId');
   309→
   310→    if (!jobId) {
   311→      return c.json(
   312→        error(ErrorCodes.VALIDATION_ERROR, 'jobId is required', requestId),
   313→        400
   314→      );
   315→    }
   316→
   317→    const result = await service.getExportJobStatus(jobId);
   318→
   319→    return c.json(
   320→      success(
   321→        {
   322→          jobId: result.jobId,
   323→          status: result.status,
   324→          ...(result.downloadUrl && { downloadUrl: result.downloadUrl }),
   325→          ...(result.expiresAt && { expiresAt: result.expiresAt }),
   326→          ...(result.fileSizeBytes && { fileSizeBytes: result.fileSizeBytes }),
   327→          ...(result.errorMessage && { errorMessage: result.errorMessage }),
   328→          ...(result.progress !== undefined && { progress: result.progress }),
   329→        },
   330→        { timing: { durationMs: getRequestDuration(c) } }
   331→      ),
   332→      200
   333→    );
   334→  } catch (err) {
   335→    if (err instanceof Error && err.message.includes('not found')) {
   336→      return c.json(
   337→        error(ErrorCodes.NOT_FOUND, 'Export job not found', requestId, {
   338→          jobId: c.req.param('jobId'),
   339→        }),
   340→        404
   341→      );
   342→    }
   343→
   344→    const message = err instanceof Error ? err.message : 'Failed to get job status';
   345→    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   346→  }
   347→});
   348→
   349→/**
   350→ * POST /export/cleanup
   351→ *
   352→ * Trigger cleanup of expired export jobs.
   353→ * Admin-only endpoint.
   354→ */
   355→exportRoutes.post('/export/cleanup', async (c) => {
   356→  const requestId = getRequestId(c);
   357→  const service = getService();
   358→
   359→  try {
   360→    const cleanedCount = service.cleanupExpiredExports();
   361→
   362→    return c.json(
   363→      success(
   364→        {
   365→          message: 'Cleanup completed',
   366→          cleanedCount,
   367→        },
   368→        { timing: { durationMs: getRequestDuration(c) } }
   369→      ),
   370→      200
   371→    );
   372→  } catch (err) {
   373→    const message = err instanceof Error ? err.message : 'Failed to cleanup exports';
   374→    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   375→  }
   376→});
   377→
   378→/**
   379→ * GET /export/download/:filename
   380→ *
   381→ * Download a generated export file.
   382→ *
   383→ * Path Parameters:
   384→ * - filename: Name of the file to download
   385→ *
   386→ * Security:
   387→ * - Validates filename to prevent path traversal attacks
   388→ * - Only serves files from the configured reports directory
   389→ *
   390→ * @returns Binary file stream with appropriate Content-Type header
   391→ */
   392→exportRoutes.get('/export/download/:filename', async (c) => {
   393→  const requestId = getRequestId(c);
   394→  const filename = c.req.param('filename');
   395→
   396→  // Validate filename format - must be alphanumeric with limited special chars
   397→  if (!filename || !/^[a-zA-Z0-9_-]+\.(pdf|xlsx|csv)$/.test(filename)) {
   398→    return c.json(
   399→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid filename format', requestId, {
   400→        pattern: '^[a-zA-Z0-9_-]+\\.(pdf|xlsx|csv)$',
   401→      }),
   402→      400
   403→    );
   404→  }
   405→
   406→  // Prevent path traversal
   407→  const safeName = path.basename(filename);
   408→  const filePath = path.join(REPORTS_OUTPUT_DIR, safeName);
   409→
   410→  // Verify the resolved path is within the allowed directory
   411→  const resolvedPath = path.resolve(filePath);
   412→  const resolvedDir = path.resolve(REPORTS_OUTPUT_DIR);
   413→  if (!resolvedPath.startsWith(resolvedDir)) {
   414→    return c.json(
   415→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid filename', requestId),
   416→      400
   417→    );
   418→  }
   419→
   420→  try {
   421→    // Check if file exists
   422→    const stats = await fs.promises.stat(filePath);
   423→    if (!stats.isFile()) {
   424→      return c.json(
   425→        error(ErrorCodes.NOT_FOUND, 'File not found', requestId),
   426→        404
   427→      );
   428→    }
   429→
   430→    // Determine content type
   431→    const ext = path.extname(safeName).toLowerCase();
   432→    const contentType = MIME_TYPES[ext] || 'application/octet-stream';
   433→
   434→    // Read file and stream response
   435→    const fileBuffer = await fs.promises.readFile(filePath);
   436→
   437→    // Set headers
   438→    c.header('Content-Type', contentType);
   439→    c.header('Content-Length', stats.size.toString());
   440→    c.header('Content-Disposition', `attachment; filename="${safeName}"`);
   441→    c.header('Cache-Control', 'private, max-age=3600');
   442→
   443→    return c.body(fileBuffer);
   444→  } catch (err) {
   445→    if (err && typeof err === 'object' && 'code' in err && err.code === 'ENOENT') {
   446→      return c.json(
   447→        error(ErrorCodes.NOT_FOUND, 'File not found', requestId, { filename: safeName }),
   448→        404
   449→      );
   450→    }
   451→
   452→    const message = err instanceof Error ? err.message : 'Failed to download file';
   453→    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   454→  }
   455→});
