   354→// Worker Registration
   355→// =============================================================================
   356→
   357→/**
   358→ * Register the optimizer worker
   359→ */
   360→export function registerOptimizerWorker() {
   361→  // Dynamic import to avoid circular dependency
   362→  // Worker registration is done in the worker startup script
   363→  log.info('Optimizer worker processor registered');
   364→}
