   241→
   242→  if (trainIds.length > 0) {
   243→    conditions.push(inArray(pmSchedule.trainId, trainIds));
   244→  }
   245→
   246→  const results = await db
   247→    .select({
   248→      pmId: pmSchedule.id,
   249→      trainId: pmSchedule.trainId,
