   297→      { pmId: pm.pmId, type: 'COMPLIANCE_END', date: pm.constraintEnd }
   298→    );
   299→  }
   300→
   301→  return c.json(
   302→    success(
   303→      {
   304→        pmBlocks,
   305→        constraintWalls,
   306→      },
   307→      { timing: { durationMs: getRequestDuration(c) } }
