  1226→
  1227→  // Calculate date range
  1228→  const today = new Date();
  1229→  const defaultFromDate = new Date(today);
  1230→  const defaultToDate = new Date(today);
  1231→  defaultToDate.setDate(defaultToDate.getDate() + 12 * 7); // 12 weeks
  1232→
  1233→  let fromDate: Date;
