  1287→    .from(baselinePmSchedule)
  1288→    .innerJoin(trains, eq(baselinePmSchedule.trainId, trains.id))
  1289→    .innerJoin(pmTypes, eq(baselinePmSchedule.pmTypeId, pmTypes.id))
  1290→    .where(and(...baselineConditions))
  1291→    .orderBy(baselinePmSchedule.projectedDate);
  1292→
  1293→  // Query current PM schedule for comparison
  1294→  const currentConditions = [
  1295→    gte(pmSchedule.targetDate, fromDateStr),
  1296→    lte(pmSchedule.targetDate, toDateStr),
  1297→    isNull(pmSchedule.scenarioId), // Production schedule only
  1298→  ];
  1299→
  1300→  if (trainIdFilter.length > 0) {
  1301→    currentConditions.push(inArray(pmSchedule.trainId, trainIdFilter));
  1302→  }
  1303→
  1304→  const currentPms = await db
  1305→    .select({
  1306→      pmId: pmSchedule.id,
