  1311→    .from(pmSchedule)
  1312→    .where(and(...currentConditions));
  1313→
  1314→  // Build a map of current PM positions by train+pmType+date (or nearest)
  1315→  const currentPmMap = new Map<string, { pmId: string; targetDate: string }>();
  1316→  for (const pm of currentPms) {
  1317→    // Key by train+pmType (we'll find the closest match)
  1318→    const key = `${pm.trainId}:${pm.pmTypeId}`;
  1319→    const existing = currentPmMap.get(key);
  1320→    if (!existing || pm.targetDate < existing.targetDate) {
