  1440→
  1441→/**
  1442→ * GET /canvas/bow-wave
  1443→ *
  1444→ * Get bow-wave analysis data showing maintenance clustering risk.
  1445→ * Bow-wave occurs when PM work accumulates in later periods, causing
  1446→ * operational overload. This data is derived from strategic planner analysis.
  1447→ *
  1448→ * Thresholds:
  1449→ * - >15 PMs/month = warning (yellow)
  1450→ * - >40% fleet in simultaneous maintenance = critical (red)
  1451→ * - Second half load > 1.5x first half = bow-wave detected
  1452→ *
  1453→ * Query Parameters:
  1454→ * - fleetId: Filter by fleet (UUID, optional)
  1455→ * - planId: Use specific strategic plan (UUID, optional - defaults to latest)
  1456→ *
  1457→ * @see specs/006-user-interface.md Section 6.5 - BowWaveIndicator
  1458→ * @see specs/004-domain-services.md Section 4.6 - Strategic Planner (bow-wave detection)
  1459→ */
  1460→canvasRoutes.get('/canvas/bow-wave', async (c) => {
  1461→  const requestId = getRequestId(c);
  1462→
  1463→  const fleetIdParam = c.req.query('fleetId');
  1464→  const planIdParam = c.req.query('planId');
  1465→
  1466→  if (fleetIdParam && !isValidUuid(fleetIdParam)) {
  1467→    return c.json(
  1468→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid fleet ID format', requestId),
  1469→      400
  1470→    );
  1471→  }
  1472→
  1473→  if (planIdParam && !isValidUuid(planIdParam)) {
  1474→    return c.json(
  1475→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid plan ID format', requestId),
  1476→      400
  1477→    );
  1478→  }
  1479→
  1480→  // Calculate quarterly PM loads for the next 10 years
  1481→  const currentYear = new Date().getFullYear();
  1482→  const horizonYears = 10;
  1483→  const endYear = currentYear + horizonYears;
  1484→
  1485→  // Build conditions for PM query
  1486→  const pmConditions = [
  1487→    gte(pmSchedule.targetDate, `${currentYear}-01-01`),
  1488→    lte(pmSchedule.targetDate, `${endYear}-12-31`),
  1489→    isNull(pmSchedule.scenarioId),
  1490→  ];
  1491→
  1492→  if (fleetIdParam) {
  1493→    pmConditions.push(eq(trains.fleetId, fleetIdParam));
  1494→  }
  1495→
  1496→  // Query PM counts by quarter
  1497→  const quarterlyResults = await db
  1498→    .select({
  1499→      year: sql<number>`EXTRACT(YEAR FROM ${pmSchedule.targetDate})::integer`.as('year'),
  1500→      quarter: sql<number>`EXTRACT(QUARTER FROM ${pmSchedule.targetDate})::integer`.as('quarter'),
  1501→      pmCount: sql<number>`COUNT(${pmSchedule.id})::integer`.as('pm_count'),
  1502→      totalHours: sql<string>`COALESCE(SUM(${pmSchedule.assignedHours}), 0)`.as('total_hours'),
  1503→    })
  1504→    .from(pmSchedule)
  1505→    .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
  1506→    .where(and(...pmConditions))
  1507→    .groupBy(
  1508→      sql`EXTRACT(YEAR FROM ${pmSchedule.targetDate})`,
  1509→      sql`EXTRACT(QUARTER FROM ${pmSchedule.targetDate})`
  1510→    )
  1511→    .orderBy(
  1512→      sql`EXTRACT(YEAR FROM ${pmSchedule.targetDate})`,
  1513→      sql`EXTRACT(QUARTER FROM ${pmSchedule.targetDate})`
  1514→    );
  1515→
  1516→  // Transform quarterly results
  1517→  type BowWaveRiskLevel = 'LOW' | 'MEDIUM' | 'HIGH' | 'CRITICAL';
  1518→
  1519→  const quarterlyLoads = quarterlyResults.map((row) => {
  1520→    const hours = parseFloat(row.totalHours) || 0;
  1521→    // Estimate capacity utilization (assuming 160 hours/quarter/track average)
  1522→    const estimatedCapacity = 640; // 4 tracks * 160 hours
  1523→    const utilizationPct = Math.round((hours / estimatedCapacity) * 100);
  1524→
  1525→    return {
  1526→      quarter: `${row.year} Q${row.quarter}`,
  1527→      year: row.year,
  1528→      quarterNum: row.quarter,
  1529→      pmCount: row.pmCount,
  1530→      totalHours: Math.round(hours * 10) / 10,
  1531→      capacityUtilizationPct: Math.min(utilizationPct, 200), // Cap at 200%
  1532→    };
  1533→  });
  1534→
  1535→  // Calculate first-half vs second-half load distribution
  1536→  const midpoint = Math.floor(quarterlyLoads.length / 2);
  1537→  const firstHalfLoads = quarterlyLoads.slice(0, midpoint);
  1538→  const secondHalfLoads = quarterlyLoads.slice(midpoint);
  1539→
  1540→  const firstHalfTotal = firstHalfLoads.reduce((sum, q) => sum + q.pmCount, 0);
  1541→  const secondHalfTotal = secondHalfLoads.reduce((sum, q) => sum + q.pmCount, 0);
  1542→  const loadImbalanceRatio = firstHalfTotal > 0 ? secondHalfTotal / firstHalfTotal : 1;
  1543→
  1544→  // Calculate risk score based on imbalance
  1545→  // Score = 0 if balanced, increases as second half exceeds first half
  1546→  let riskScore = 0;
  1547→  if (loadImbalanceRatio > 1) {
  1548→    // Risk increases from 0 to 1 as ratio goes from 1 to 2
  1549→    riskScore = Math.min(1, (loadImbalanceRatio - 1) / 1);
  1550→  }
  1551→
  1552→  // Determine risk level
  1553→  let riskLevel: BowWaveRiskLevel;
  1554→  if (riskScore < 0.25) {
  1555→    riskLevel = 'LOW';
  1556→  } else if (riskScore < 0.5) {
  1557→    riskLevel = 'MEDIUM';
  1558→  } else if (riskScore < 0.75) {
  1559→    riskLevel = 'HIGH';
  1560→  } else {
  1561→    riskLevel = 'CRITICAL';
  1562→  }
  1563→
  1564→  // Identify peak periods (quarters with >15 PMs/month equivalent)
  1565→  interface BowWavePeakPeriod {
  1566→    startQuarter: string;
  1567→    endQuarter: string;
  1568→    averageLoad: number;
  1569→    peakLoad: number;
  1570→    riskLevel: BowWaveRiskLevel;
  1571→  }
  1572→
  1573→  const peakPeriods: BowWavePeakPeriod[] = [];
  1574→  let currentPeak: {
  1575→    start: string;
  1576→    end: string;
  1577→    loads: number[];
  1578→    peak: number;
  1579→  } | null = null;
  1580→
  1581→  for (const q of quarterlyLoads) {
  1582→    const monthlyAvg = q.pmCount / 3;
  1583→    const isPeak = monthlyAvg > 15; // >15 PMs/month threshold
  1584→
  1585→    if (isPeak) {
  1586→      if (!currentPeak) {
  1587→        currentPeak = {
  1588→          start: q.quarter,
  1589→          end: q.quarter,
  1590→          loads: [q.pmCount],
  1591→          peak: q.pmCount,
  1592→        };
  1593→      } else {
  1594→        currentPeak.end = q.quarter;
  1595→        currentPeak.loads.push(q.pmCount);
  1596→        currentPeak.peak = Math.max(currentPeak.peak, q.pmCount);
  1597→      }
  1598→    } else if (currentPeak) {
  1599→      // End of peak period
  1600→      const avgLoad = Math.round(currentPeak.loads.reduce((a, b) => a + b, 0) / currentPeak.loads.length);
  1601→      const monthlyPeak = Math.round(currentPeak.peak / 3);
  1602→
  1603→      let periodRisk: BowWaveRiskLevel;
  1604→      if (monthlyPeak > 40) {
  1605→        periodRisk = 'CRITICAL';
  1606→      } else if (monthlyPeak > 25) {
  1607→        periodRisk = 'HIGH';
  1608→      } else if (monthlyPeak > 15) {
  1609→        periodRisk = 'MEDIUM';
  1610→      } else {
  1611→        periodRisk = 'LOW';
  1612→      }
  1613→
  1614→      peakPeriods.push({
  1615→        startQuarter: currentPeak.start,
  1616→        endQuarter: currentPeak.end,
  1617→        averageLoad: avgLoad,
  1618→        peakLoad: currentPeak.peak,
  1619→        riskLevel: periodRisk,
  1620→      });
  1621→
  1622→      currentPeak = null;
  1623→    }
  1624→  }
  1625→
  1626→  // Handle trailing peak period
  1627→  if (currentPeak) {
  1628→    const avgLoad = Math.round(currentPeak.loads.reduce((a, b) => a + b, 0) / currentPeak.loads.length);
  1629→    const monthlyPeak = Math.round(currentPeak.peak / 3);
  1630→
  1631→    let periodRisk: BowWaveRiskLevel;
  1632→    if (monthlyPeak > 40) {
  1633→      periodRisk = 'CRITICAL';
  1634→    } else if (monthlyPeak > 25) {
  1635→      periodRisk = 'HIGH';
  1636→    } else if (monthlyPeak > 15) {
  1637→      periodRisk = 'MEDIUM';
  1638→    } else {
  1639→      periodRisk = 'LOW';
  1640→    }
  1641→
  1642→    peakPeriods.push({
  1643→      startQuarter: currentPeak.start,
  1644→      endQuarter: currentPeak.end,
  1645→      averageLoad: avgLoad,
  1646→      peakLoad: currentPeak.peak,
  1647→      riskLevel: periodRisk,
  1648→    });
  1649→  }
  1650→
  1651→  // Generate recommendations based on analysis
  1652→  type RecommendationType = 'ADVANCE_PM' | 'DEFER_PM' | 'ADD_CAPACITY' | 'SPREAD_WORKLOAD';
  1653→  type RecommendationPriority = 'HIGH' | 'MEDIUM' | 'LOW';
  1654→
  1655→  interface BowWaveRecommendation {
  1656→    type: RecommendationType;
  1657→    description: string;
  1658→    impact: string;
  1659→    priority: RecommendationPriority;
  1660→  }
  1661→
  1662→  const recommendations: BowWaveRecommendation[] = [];
  1663→
  1664→  if (riskLevel === 'CRITICAL' || riskLevel === 'HIGH') {
  1665→    recommendations.push({
  1666→      type: 'SPREAD_WORKLOAD',
  1667→      description: 'Redistribute PM load from second half to first half of planning horizon',
  1668→      impact: `Could reduce imbalance ratio from ${loadImbalanceRatio.toFixed(2)}x to ~1.2x`,
  1669→      priority: 'HIGH',
  1670→    });
  1671→  }
  1672→
  1673→  if (peakPeriods.some(p => p.riskLevel === 'CRITICAL')) {
  1674→    recommendations.push({
  1675→      type: 'ADVANCE_PM',
  1676→      description: 'Advance non-critical PMs from peak periods to earlier quarters',
  1677→      impact: 'Reduces peak load and prevents operational bottlenecks',
  1678→      priority: 'HIGH',
  1679→    });
  1680→  }
  1681→
  1682→  if (peakPeriods.length > 2) {
  1683→    recommendations.push({
  1684→      type: 'ADD_CAPACITY',
  1685→      description: 'Consider contractor support during peak periods',
  1686→      impact: 'Increases throughput by 20-30% during critical periods',
  1687→      priority: 'MEDIUM',
  1688→    });
  1689→  }
  1690→
  1691→  if (riskLevel === 'MEDIUM') {
  1692→    recommendations.push({
  1693→      type: 'DEFER_PM',
  1694→      description: 'Review PMs that can be safely deferred within compliance windows',
  1695→      impact: 'Smooths workload distribution across quarters',
  1696→      priority: 'LOW',
  1697→    });
  1698→  }
  1699→
  1700→  // Get affected fleets
  1701→  const fleetConditions = fleetIdParam
  1702→    ? [eq(fleets.id, fleetIdParam)]
  1703→    : [];
  1704→
  1705→  const affectedFleetsResult = await db
  1706→    .select({ code: fleets.code })
  1707→    .from(fleets)
  1708→    .where(fleetConditions.length > 0 ? and(...fleetConditions) : undefined)
  1709→    .orderBy(fleets.code);
  1710→
  1711→  const affectedFleets = affectedFleetsResult.map((f) => f.code);
  1712→
  1713→  // Build response
  1714→  const bowWaveData = {
  1715→    riskLevel,
  1716→    riskScore: Math.round(riskScore * 100) / 100,
  1717→    planId: planIdParam ?? null,
  1718→    planDate: new Date().toISOString().split('T')[0],
  1719→    quarterlyLoads,
  1720→    peakPeriods,
  1721→    recommendations,
  1722→    summary: {
  1723→      totalPms: firstHalfTotal + secondHalfTotal,
  1724→      firstHalfLoad: firstHalfTotal,
  1725→      secondHalfLoad: secondHalfTotal,
  1726→      loadImbalanceRatio: Math.round(loadImbalanceRatio * 100) / 100,
  1727→      affectedFleets,
  1728→    },
  1729→  };
  1730→
  1731→  return c.json(
  1732→    success(bowWaveData, { timing: { durationMs: getRequestDuration(c) } })
  1733→  );
  1734→});
