   434→    onProgress: ProgressCallback | undefined,
   435→    onResult: (result: OptimizerFullResult) => void,
   436→    onError: (error: Error) => void
   437→  ): void {
   438→    switch (msg.type) {
   439→      case 'HEARTBEAT':
   440→        this.lastHeartbeat = Date.now();
   441→        break;
   442→
   443→      case 'PROGRESS':
   444→        this.lastHeartbeat = Date.now();
   445→        if (onProgress) {
   446→          onProgress(msg);
   447→        }
   448→        break;
   449→
   450→      case 'ERROR':
   451→        onError(
