   453→            requestId,
   454→            errorCode: msg.errorCode,
   455→            recoverySuggestion: msg.recoverySuggestion,
   456→          })
   457→        );
   458→        break;
   459→
   460→      case 'RESULT':
   461→        onResult(this.transformResultFromCpp(msg as unknown as Record<string, unknown>));
