     1→/**
     2→ * MMS WebSocket Server
     3→ *
     4→ * Bun-native WebSocket server implementation for real-time communication.
     5→ * Creates a separate WebSocket server that runs alongside the HTTP API.
     6→ *
     7→ * Usage:
     8→ *   import { createWebSocketServer } from './server';
     9→ *   const wsServer = createWebSocketServer({ port: 3001 });
    10→ *
    11→ * Connection:
    12→ *   const ws = new WebSocket('ws://localhost:3001/ws');
    13→ *   ws.onopen = () => {
    14→ *     ws.send(JSON.stringify({ type: 'AUTH', data: { token: 'jwt-token' } }));
    15→ *   };
    16→ *
    17→ * @see specs/005-api.md Section 5.14 (WebSocket Events)
    18→ */
    19→
    20→import type { ServerWebSocket } from 'bun';
    21→import { logger } from '../../lib/logging/logger';
    22→import { getWebSocketHub, createConnectionId, type WebSocketData } from './hub';
    23→
    24→// =============================================================================
    25→// Types
    26→// =============================================================================
    27→
    28→export interface WebSocketServerConfig {
    29→  port: number;
    30→  hostname?: string;
    31→  path?: string;
    32→}
    33→
    34→/** Bun server with WebSocket support */
    35→type BunServer = ReturnType<typeof Bun.serve<WebSocketData>>;
    36→
    37→export interface WebSocketServerInstance {
    38→  server: BunServer;
    39→  stop: () => void;
    40→}
    41→
    42→// =============================================================================
    43→// Server Factory
    44→// =============================================================================
    45→
    46→/**
    47→ * Create a Bun WebSocket server
    48→ */
    49→export function createWebSocketServer(config: WebSocketServerConfig): WebSocketServerInstance {
    50→  const { port, hostname = '0.0.0.0', path = '/ws' } = config;
    51→  const hub = getWebSocketHub();
    52→  const log = logger.child({ service: 'websocket-server' });
    53→
    54→  const server = Bun.serve<WebSocketData>({
    55→    port,
    56→    hostname,
    57→
    58→    fetch(req, server) {
    59→      const url = new URL(req.url);
    60→
    61→      // Health check endpoint
    62→      if (url.pathname === '/health') {
    63→        const stats = hub.getStats();
    64→        return new Response(
    65→          JSON.stringify({
    66→            status: 'healthy',
    67→            timestamp: new Date().toISOString(),
    68→            websocket: stats,
    69→          }),
    70→          { headers: { 'Content-Type': 'application/json' } }
    71→        );
    72→      }
    73→
    74→      // WebSocket upgrade
    75→      if (url.pathname === path) {
    76→        const connectionId = createConnectionId();
    77→        const ipAddress = req.headers.get('x-forwarded-for') ??
    78→                         req.headers.get('x-real-ip') ??
    79→                         server.requestIP(req)?.address;
    80→        const userAgent = req.headers.get('user-agent') ?? undefined;
    81→
    82→        const upgraded = server.upgrade(req, {
    83→          data: {
    84→            connectionId,
    85→            ipAddress: ipAddress ?? undefined,
    86→            userAgent,
    87→          },
    88→        });
    89→
    90→        if (!upgraded) {
    91→          return new Response('WebSocket upgrade failed', { status: 500 });
    92→        }
    93→
    94→        return undefined;
    95→      }
    96→
    97→      // 404 for other routes
    98→      return new Response('Not Found', { status: 404 });
    99→    },
   100→
   101→    websocket: {
   102→      open(ws: ServerWebSocket<WebSocketData>) {
   103→        hub.onOpen(ws);
   104→      },
   105→
   106→      async message(ws: ServerWebSocket<WebSocketData>, message: string | Buffer) {
   107→        await hub.onMessage(ws, message);
   108→      },
   109→
   110→      close(ws: ServerWebSocket<WebSocketData>, code: number, reason: string) {
   111→        hub.onClose(ws, code, reason);
   112→      },
   113→
   114→      // Bun WebSocket options
   115→      maxPayloadLength: 64 * 1024, // 64KB max message size
   116→      idleTimeout: 120, // 2 minutes idle timeout
   117→      backpressureLimit: 1024 * 1024, // 1MB backpressure limit
   118→      closeOnBackpressureLimit: true,
   119→      sendPings: true,
   120→    },
   121→  });
   122→
   123→  // Start the hub
   124→  hub.start();
   125→
   126→  log.info({ port, hostname, path }, 'WebSocket server started');
   127→
   128→  return {
   129→    server,
   130→    stop: () => {
   131→      hub.stop();
   132→      server.stop();
   133→      log.info('WebSocket server stopped');
   134→    },
   135→  };
   136→}
   137→
   138→/**
   139→ * Upgrade an existing HTTP request to WebSocket (for Hono integration)
   140→ */
   141→export function handleWebSocketUpgrade(
   142→  req: Request,
   143→  server: BunServer
   144→): Response | undefined {
   145→  const connectionId = createConnectionId();
   146→  const ipAddress = req.headers.get('x-forwarded-for') ??
   147→                   req.headers.get('x-real-ip') ?? undefined;
   148→  const userAgent = req.headers.get('user-agent') ?? undefined;
   149→
   150→  const upgraded = server.upgrade(req, {
   151→    data: {
   152→      connectionId,
   153→      ipAddress,
   154→      userAgent,
   155→    },
   156→  });
   157→
   158→  if (!upgraded) {
   159→    return new Response('WebSocket upgrade failed', { status: 500 });
   160→  }
   161→
   162→  return undefined;
   163→}
